$toolDefinition_disk_analyzer = array (
  'type' => 'function',
  'function' => 
  array (
    'name' => 'disk_analyzer',
    'description' => 'Analyze disk drives and storage using PHP\'s FFI to call Windows API functions (GetLogicalDrives, GetDriveTypeA, GetDiskFreeSpaceExA, GetVolumeInformationA). Returns: list of all drives, their types (fixed/removable/CD-ROM/network/RAM), total/free/used space in GB and percentage, volume labels, file system types, and serial numbers. No native PHP function provides drive enumeration or volume labels — FFI is required. First storage/disk analysis capability in the ecosystem. Never throws — all errors returned as structured data.',
    'parameters' => 
    array (
      'type' => 'object',
      'properties' => 
      array (
        'timeout' => 
        array (
          'type' => 'integer',
          'description' => 'Timeout in seconds (1-10, default: 5).',
        ),
      ),
      'required' => 
      array (
      ),
    ),
  ),
);

if (! function_exists('disk_analyzer')) {
    function disk_analyzer($timeout = null)
    {
        // Disk analyzer - uses FFI to call Windows disk API functions
        // Returns drive list, types, space usage, volume labels, and file systems

        $timeout = isset($timeout) ? min(max((int)$timeout, 1), 10) : 5;

        $result = [
            'success' => true,
            'os_family' => PHP_OS_FAMILY,
            'ffi_available' => extension_loaded('ffi'),
        ];

        if (!$result['ffi_available']) {
            return array_merge($result, ['error' => 'FFI extension not loaded']);
        }

        if (PHP_OS_FAMILY !== 'Windows') {
            // Unix fallback: use PHP's built-in disk functions
            return array_merge($result, [
                'note' => 'Unix/Linux - using PHP disk functions',
                'message' => 'Full drive enumeration requires FFI on Windows. On Unix, use disk_free_space/disk_total_space.'
            ]);
        }

        try {
            // Load kernel32.dll
            $kernel = FFI::cdef("
                unsigned long GetLogicalDrives(void);
                unsigned long GetDriveTypeA(const char* lpRootPathName);
                int GetDiskFreeSpaceExA(
                    const char* lpDirectoryName,
                    unsigned long long* lpFreeBytesAvailable,
                    unsigned long long* lpTotalNumberOfBytes,
                    unsigned long long* lpTotalNumberOfFreeBytes
                );
                int GetVolumeInformationA(
                    const char* lpRootPathName,
                    char* lpVolumeNameBuffer,
                    unsigned long nVolumeNameSize,
                    unsigned long* lpVolumeSerialNumber,
                    unsigned long* lpMaximumComponentLength,
                    unsigned long* lpFileSystemFlags,
                    char* lpFileSystemNameBuffer,
                    unsigned long nFileSystemNameSize
                );
            ", "kernel32.dll");
            
            // Get drive bitmask
            $mask = (int)$kernel->GetLogicalDrives();
            $result['drive_bitmask'] = '0x' . dechex($mask);
            
            $drive_types = [
                0 => 'unknown',
                1 => 'no_root',
                2 => 'removable',
                3 => 'fixed',
                4 => 'network',
                5 => 'cdrom',
                6 => 'ramdisk',
            ];
            
            $drives = [];
            $total_space_all = 0;
            $total_free_all = 0;
            
            for ($i = 0; $i < 26; $i++) {
                if ($mask & (1 << $i)) {
                    $letter = chr(65 + $i);
                    $path = $letter . ':\\';
                    
                    $drive_info = [
                        'drive' => $letter . ':',
                        'path' => $path,
                    ];
                    
                    // Drive type
                    $type_code = (int)$kernel->GetDriveTypeA($path);
                    $drive_info['type_code'] = $type_code;
                    $drive_info['type'] = $drive_types[$type_code] ?? "unknown({$type_code})";
                    
                    // Disk space
                    $freeAvail = $kernel->new("unsigned long long");
                    $totalBytes = $kernel->new("unsigned long long");
                    $totalFree = $kernel->new("unsigned long long");
                    
                    $space_ret = $kernel->GetDiskFreeSpaceExA($path, FFI::addr($freeAvail), FFI::addr($totalBytes), FFI::addr($totalFree));
                    
                    if ($space_ret) {
                        $total_val = (int)$totalBytes->cdata;
                        $free_val = (int)$freeAvail->cdata;
                        $used_val = $total_val - $free_val;
                        
                        $totalGB = $total_val / 1073741824.0;
                        $freeGB = $free_val / 1073741824.0;
                        $usedGB = $used_val / 1073741824.0;
                        $used_pct = $total_val > 0 ? round(($used_val / $total_val) * 100, 1) : 0;
                        
                        $drive_info['total_bytes'] = $total_val;
                        $drive_info['free_bytes'] = $free_val;
                        $drive_info['used_bytes'] = $used_val;
                        $drive_info['total_gb'] = round($totalGB, 2);
                        $drive_info['free_gb'] = round($freeGB, 2);
                        $drive_info['used_gb'] = round($usedGB, 2);
                        $drive_info['used_percent'] = $used_pct;
                        
                        $total_space_all += $total_val;
                        $total_free_all += $free_val;
                    }
                    
                    // Volume information
                    $volName = $kernel->new("char[256]");
                    $serialNum = $kernel->new("unsigned long");
                    $maxCompLen = $kernel->new("unsigned long");
                    $fsFlags = $kernel->new("unsigned long");
                    $fsName = $kernel->new("char[256]");
                    
                    $vol_ret = $kernel->GetVolumeInformationA(
                        $path, $volName, 256,
                        FFI::addr($serialNum), FFI::addr($maxCompLen), FFI::addr($fsFlags),
                        $fsName, 256
                    );
                    
                    if ($vol_ret) {
                        $vol_label = trim(FFI::string($volName));
                        $drive_info['volume_label'] = $vol_label !== '' ? $vol_label : '(no label)';
                        $drive_info['file_system'] = trim(FFI::string($fsName));
                        $drive_info['serial_number'] = strtoupper(dechex((int)$serialNum->cdata));
                    }
                    
                    $drives[] = $drive_info;
                }
            }
            
            $result['drive_count'] = count($drives);
            $result['drives'] = $drives;
            
            // Summary
            $total_all_gb = $total_space_all / 1073741824.0;
            $total_free_gb = $total_free_all / 1073741824.0;
            $total_used_gb = $total_all_gb - $total_free_gb;
            
            $result['summary'] = [
                'total_space_gb' => round($total_all_gb, 2),
                'total_free_gb' => round($total_free_gb, 2),
                'total_used_gb' => round($total_used_gb, 2),
                'overall_used_percent' => $total_all_gb > 0 ? round(($total_used_gb / $total_all_gb) * 100, 1) : 0,
            ];
            
            // Warning if any drive is critically low on space
            $critical = [];
            foreach ($drives as $d) {
                if (isset($d['used_percent']) && $d['used_percent'] > 90 && $d['type'] === 'fixed') {
                    $critical[] = "{$d['drive']} at {$d['used_percent']}% capacity ({$d['free_gb']} GB free)";
                }
            }
            if (count($critical) > 0) {
                $result['warnings'] = $critical;
            }
            
            return $result;
            
        } catch (\Throwable $e) {
            return array_merge($result, [
                'error' => 'Disk analysis via FFI failed: ' . $e->getMessage(),
            ]);
        }
    }
}
